class BookMyShow {
    private final int n, m;
    private final long[] sum;
    private final int[] max;
    private final int[] left;
    private final int[] right;

    public BookMyShow(int n, int m) {
        this.n = n;
        this.m = m;
        int size = 1;
        while (size < n) size <<= 1;
        sum = new long[2 * size];
        max = new int[2 * size];
        left = new int[2 * size];
        right = new int[2 * size];
        for (int i = 0; i < n; ++i) {
            sum[size + i] = m;
            max[size + i] = m;
            left[size + i] = i;
            right[size + i] = i;
        }
        for (int i = size - 1; i > 0; --i) {
            int l = i << 1;
            int r = l + 1;
            sum[i] = sum[l] + sum[r];
            max[i] = Math.max(max[l], max[r]);
            left[i] = left[l];
            right[i] = right[r];
        }
    }

    public int[] gather(int k, int maxRow) {
        int idx = findGather(1, k, maxRow);
        if (idx == -1) return new int[0];
        int row = idx;
        int start = (int) (m - max[idx + n]);
        reserve(row, k);
        return new int[]{row, start};
    }

    public boolean scatter(int k, int maxRow) {
        long total = querySum(1, 0, maxRow);
        if (total < k) return false;
        int rem = k;
        while (rem > 0) {
            int row = findScatter(1, rem, maxRow);
            if (row == -1) break;
            int take = Math.min(rem, max[row + n]);
            reserve(row, take);
            rem -= take;
        }
        return true;
    }

    private int findGather(int node, int k, int maxRow) {
        if (max[node] < k) return -1;
        if (left[node] > maxRow) return -1;
        if (left[node] == right[node]) return left[node];
        int l = node << 1;
        int r = l + 1;
        int res = findGather(l, k, maxRow);
        if (res != -1) return res;
        return findGather(r, k, maxRow);
    }

    private long querySum(int node, int l, int r) {
        if (left[node] > r || right[node] < l) return 0;
        if (l <= left[node] && right[node] <= r) return sum[node];
        return querySum(node << 1, l, r) + querySum((node << 1) + 1, l, r);
    }

    private int findScatter(int node, int k, int maxRow) {
        if (sum[node] == 0 || left[node] > maxRow) return -1;
        if (left[node] == right[node]) return left[node];
        int l = node << 1;
        int r = l + 1;
        int res = findScatter(l, k, maxRow);
        if (res != -1) return res;
        return findScatter(r, k, maxRow);
    }

    private void reserve(int row, int k) {
        int node = n + row;
        sum[node] -= k;
        max[node] -= k;
        for (node >>= 1; node > 0; node >>= 1) {
            int l = node << 1;
            int r = l + 1;
            sum[node] = sum[l] + sum[r];
            max[node] = Math.max(max[l], max[r]);
        }
    }
}
